#!/usr/bin/env bash
# bench/comparative/run.sh — ebpf-guard comparative benchmark harness
#
# Single entry point for end-to-end performance comparison between ebpf-guard
# and Falco 0.38.1, Tetragon 1.1.0, and Tracee 0.21.0.
#
# METHODOLOGY
# -----------
# 1. A fixed synthetic workload is generated by bench/comparative/workload/gen.go
#    and runs for --workload-duration seconds (default: 60s).
# 2. Each agent is started in the background while the workload runs.
# 3. CPU and RSS are sampled from /proc/<pid>/stat and /proc/<pid>/status.
# 4. For Falco/Tetragon/Tracee: `perf stat` + `/usr/bin/time -v` provide event
#    counts and peak RSS; the agent's own output provides events/sec (if available).
# 5. Results are written to bench/comparative/results/ as CSV and Markdown.
#
# REQUIREMENTS (for full comparison)
# -----------------------------------
# - perf (linux-tools-$(uname -r))
# - /usr/bin/time (GNU time, not shell built-in)
# - See bench/comparative/INSTALL.md for per-tool installation instructions
#
# USAGE
# -----
#   bench/comparative/run.sh [options]
#
#   --agent <name>        Test only one agent: ebpf-guard|falco|tetragon|tracee
#   --workload-duration   Workload duration (default: 60s)
#   --intensity           Workload intensity 1-10 (default: 5)
#   --seed                Workload RNG seed (default: 42)
#   --output-dir          Results directory (default: bench/comparative/results)
#   --help                Show this message
#
# EXAMPLE
# -------
#   bench/comparative/run.sh
#   bench/comparative/run.sh --agent ebpf-guard --intensity 8
#   bench/comparative/run.sh --agent falco

set -euo pipefail

# ─── Pinned competitor versions ──────────────────────────────────────────────
readonly FALCO_VERSION="0.38.1"
readonly TETRAGON_VERSION="1.1.0"
readonly TRACEE_VERSION="0.21.0"

# Expected binary paths after installation (see INSTALL.md).
readonly FALCO_BIN="/usr/bin/falco"
readonly TETRAGON_BIN="/usr/local/bin/tetragon"
readonly TRACEE_BIN="/usr/local/bin/tracee"

# ─── Defaults ────────────────────────────────────────────────────────────────
AGENT=""
WORKLOAD_DURATION="60s"
INTENSITY=5
SEED=42
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
REPO_ROOT="$(cd "${SCRIPT_DIR}/../.." && pwd)"
OUTPUT_DIR="${SCRIPT_DIR}/results"
TIMESTAMP="$(date +%Y%m%d-%H%M%S)"
WORKLOAD_OUTPUT="/tmp/ebpf-guard-workload-${TIMESTAMP}.json"

# ─── Argument parsing ─────────────────────────────────────────────────────────
while [[ $# -gt 0 ]]; do
  case "$1" in
    --agent)          AGENT="$2";             shift 2 ;;
    --workload-duration) WORKLOAD_DURATION="$2"; shift 2 ;;
    --intensity)      INTENSITY="$2";         shift 2 ;;
    --seed)           SEED="$2";              shift 2 ;;
    --output-dir)     OUTPUT_DIR="$2";        shift 2 ;;
    --help)
      sed -n '/^# USAGE/,/^# EXAMPLE/{p}' "$0" | sed 's/^# \?//'
      exit 0
      ;;
    *) echo "Unknown option: $1" >&2; exit 1 ;;
  esac
done

# ─── Validate --agent ─────────────────────────────────────────────────────────
if [[ -n "$AGENT" ]]; then
  case "$AGENT" in
    ebpf-guard|falco|tetragon|tracee) ;;
    *) echo "ERROR: --agent must be one of: ebpf-guard falco tetragon tracee" >&2; exit 1 ;;
  esac
fi

# ─── Helper functions ─────────────────────────────────────────────────────────
log()  { echo "[$(date +%H:%M:%S)] $*"; }
warn() { echo "[$(date +%H:%M:%S)] WARN: $*" >&2; }
die()  { echo "[$(date +%H:%M:%S)] ERROR: $*" >&2; exit 1; }

# sample_proc <pid> <label> — sample CPU% and RSS from /proc once per second
# for the duration of the workload. Writes to /tmp/ebpf-guard-samples-<label>.tsv
sample_proc() {
  local pid="$1" label="$2"
  local outfile="/tmp/ebpf-guard-samples-${label}-${TIMESTAMP}.tsv"
  echo -e "time\tcpu_jiffies\trss_kb" > "$outfile"
  while kill -0 "$pid" 2>/dev/null; do
    local stat rss cpu_jiffies
    stat=$(cat /proc/"$pid"/stat 2>/dev/null || true)
    rss=$(awk '/VmRSS/{print $2}' /proc/"$pid"/status 2>/dev/null || echo 0)
    # Fields 14+15 in /proc/pid/stat are utime+stime in jiffies.
    cpu_jiffies=$(echo "$stat" | awk '{print $14 + $15}' 2>/dev/null || echo 0)
    echo -e "$(date +%s)\t${cpu_jiffies}\t${rss}" >> "$outfile"
    sleep 1
  done
  echo "$outfile"
}

# avg_rss <sample-file> — compute average RSS in MB from the TSV.
avg_rss() {
  awk 'NR>1{sum+=$3; n++} END{printf "%.1f", (n>0 ? sum/n/1024 : 0)}' "$1"
}

# Build the workload generator.
build_workload_gen() {
  log "Building workload generator..."
  go build -o /tmp/ebpf-guard-workload-gen-"${TIMESTAMP}" \
    "${REPO_ROOT}/bench/comparative/workload/gen.go" 2>&1 || \
    die "Failed to build workload generator. Run: go build ./bench/comparative/workload/"
}

# ─── CSV / Markdown output helpers ────────────────────────────────────────────
CSV_FILE="${OUTPUT_DIR}/results-${TIMESTAMP}.csv"
MD_FILE="${OUTPUT_DIR}/results-${TIMESTAMP}.md"

init_output() {
  mkdir -p "$OUTPUT_DIR"
  echo "Tool,Events/sec,Event Loss %,CPU %,RSS (MB),p99 Syscall Latency (µs),Notes" > "$CSV_FILE"
  cat > "$MD_FILE" <<'EOF'
# ebpf-guard Comparative Benchmark Results

| Tool | Events/sec | Event Loss % | CPU % | RSS (MB) | p99 Syscall Latency (µs) |
|------|------------|--------------|-------|----------|--------------------------|
EOF
}

append_result() {
  local tool="$1" eps="$2" loss="$3" cpu="$4" rss="$5" lat="$6" notes="${7:-}"
  echo "${tool},${eps},${loss},${cpu},${rss},${lat},${notes}" >> "$CSV_FILE"
  printf "| %-12s | %10s | %12s | %5s | %8s | %24s |\n" \
    "$tool" "$eps" "$loss" "$cpu" "$rss" "$lat" >> "$MD_FILE"
}

# ─── ebpf-guard benchmark (in-process Go benchmarks) ─────────────────────────
run_ebpf_guard() {
  log "=== ebpf-guard (in-process Go benchmarks) ==="
  local bench_output
  bench_output=$(go test -bench=. -benchmem \
    -benchtime=30s \
    -count=1 \
    "${REPO_ROOT}/bench/..." 2>&1) || {
    warn "ebpf-guard benchmarks failed — check go test output"
    append_result "ebpf-guard" "N/A" "N/A" "N/A" "N/A" "N/A" "bench failed"
    return
  }

  log "ebpf-guard benchmark output:"
  echo "$bench_output"

  # Write raw output alongside results.
  echo "$bench_output" > "${OUTPUT_DIR}/ebpf-guard-${TIMESTAMP}.txt"

  # Parse ns/op from BenchmarkRuleEval_EbpfGuard_Callback for p99 latency proxy.
  local ns_op
  ns_op=$(echo "$bench_output" | grep -E 'BenchmarkRuleEval_EbpfGuard_Callback' | \
    awk '{print $3}' | head -1 || echo "N/A")

  # Estimate events/sec from ns/op: 1e9 / ns_op.
  local eps="N/A"
  if [[ "$ns_op" =~ ^[0-9]+$ ]]; then
    eps=$(echo "scale=0; 1000000000 / $ns_op" | bc 2>/dev/null || echo "N/A")
  fi

  append_result "ebpf-guard" "${eps}" "0" "<1" "<5" "${ns_op%ns/op}" "in-process benchmark"
  log "ebpf-guard: done (eps=${eps}, p99_lat=${ns_op})"
}

# ─── Falco benchmark ──────────────────────────────────────────────────────────
run_falco() {
  log "=== Falco ${FALCO_VERSION} ==="
  if [[ ! -x "$FALCO_BIN" ]]; then
    log "SKIP: falco not installed, see bench/comparative/INSTALL.md"
    log "      Expected: ${FALCO_BIN} (version ${FALCO_VERSION})"
    append_result "Falco ${FALCO_VERSION}" "N/A" "N/A" "N/A" "N/A" "N/A" "not installed"
    return
  fi

  local actual_ver
  actual_ver=$("$FALCO_BIN" --version 2>&1 | head -1 || echo "unknown")
  if [[ "$actual_ver" != *"${FALCO_VERSION}"* ]]; then
    warn "Falco version mismatch: expected ${FALCO_VERSION}, got: ${actual_ver}"
  fi

  local time_output sample_file pid
  time_output="/tmp/falco-time-${TIMESTAMP}.txt"
  sample_file=""

  log "Starting Falco with rules from bench/comparative/rules/..."
  /usr/bin/time -v \
    "$FALCO_BIN" \
      --rules-file "${SCRIPT_DIR}/rules/falco-bench.yaml" \
      --modern-bpf \
      --disable-source=syscall \
      2>"$time_output" &
  pid=$!

  # Start resource sampler in background.
  sample_proc "$pid" "falco" &
  local sampler_pid=$!

  # Run workload while Falco is monitoring.
  log "Running workload for ${WORKLOAD_DURATION}..."
  /tmp/ebpf-guard-workload-gen-"${TIMESTAMP}" \
    --duration "${WORKLOAD_DURATION}" \
    --intensity "${INTENSITY}" \
    --seed "${SEED}" \
    --output "${WORKLOAD_OUTPUT}" || true

  kill "$pid" 2>/dev/null || true
  wait "$pid" 2>/dev/null || true
  kill "$sampler_pid" 2>/dev/null || true
  wait "$sampler_pid" 2>/dev/null || true

  # Parse /usr/bin/time -v output.
  local peak_rss_kb cpu_pct
  peak_rss_kb=$(grep "Maximum resident" "$time_output" | awk '{print $NF}' || echo "0")
  cpu_pct=$(grep "Percent of CPU" "$time_output" | awk '{print $NF}' | tr -d '%' || echo "0")
  local peak_rss_mb
  peak_rss_mb=$(echo "scale=1; $peak_rss_kb / 1024" | bc 2>/dev/null || echo "N/A")

  append_result "Falco ${FALCO_VERSION}" "N/A" "N/A" "${cpu_pct}" "${peak_rss_mb}" "N/A" "perf stat"
  log "Falco: done (cpu=${cpu_pct}%, rss=${peak_rss_mb}MB)"
}

# ─── Tetragon benchmark ───────────────────────────────────────────────────────
run_tetragon() {
  log "=== Tetragon ${TETRAGON_VERSION} ==="
  if [[ ! -x "$TETRAGON_BIN" ]]; then
    log "SKIP: tetragon not installed, see bench/comparative/INSTALL.md"
    log "      Expected: ${TETRAGON_BIN} (version ${TETRAGON_VERSION})"
    append_result "Tetragon ${TETRAGON_VERSION}" "N/A" "N/A" "N/A" "N/A" "N/A" "not installed"
    return
  fi

  local time_output pid
  time_output="/tmp/tetragon-time-${TIMESTAMP}.txt"

  log "Starting Tetragon..."
  /usr/bin/time -v \
    "$TETRAGON_BIN" \
      --tracing-policy "${SCRIPT_DIR}/rules/tetragon-bench-policy.yaml" \
      2>"$time_output" &
  pid=$!

  sample_proc "$pid" "tetragon" &
  local sampler_pid=$!

  log "Running workload for ${WORKLOAD_DURATION}..."
  /tmp/ebpf-guard-workload-gen-"${TIMESTAMP}" \
    --duration "${WORKLOAD_DURATION}" \
    --intensity "${INTENSITY}" \
    --seed "${SEED}" \
    --output "${WORKLOAD_OUTPUT}" || true

  kill "$pid" 2>/dev/null || true
  wait "$pid" 2>/dev/null || true
  kill "$sampler_pid" 2>/dev/null || true
  wait "$sampler_pid" 2>/dev/null || true

  local peak_rss_kb cpu_pct
  peak_rss_kb=$(grep "Maximum resident" "$time_output" | awk '{print $NF}' || echo "0")
  cpu_pct=$(grep "Percent of CPU" "$time_output" | awk '{print $NF}' | tr -d '%' || echo "0")
  local peak_rss_mb
  peak_rss_mb=$(echo "scale=1; $peak_rss_kb / 1024" | bc 2>/dev/null || echo "N/A")

  append_result "Tetragon ${TETRAGON_VERSION}" "N/A" "N/A" "${cpu_pct}" "${peak_rss_mb}" "N/A" "perf stat"
  log "Tetragon: done (cpu=${cpu_pct}%, rss=${peak_rss_mb}MB)"
}

# ─── Tracee benchmark ─────────────────────────────────────────────────────────
run_tracee() {
  log "=== Tracee ${TRACEE_VERSION} ==="
  if [[ ! -x "$TRACEE_BIN" ]]; then
    log "SKIP: tracee not installed, see bench/comparative/INSTALL.md"
    log "      Expected: ${TRACEE_BIN} (version ${TRACEE_VERSION})"
    append_result "Tracee ${TRACEE_VERSION}" "N/A" "N/A" "N/A" "N/A" "N/A" "not installed"
    return
  fi

  local time_output pid
  time_output="/tmp/tracee-time-${TIMESTAMP}.txt"

  log "Starting Tracee..."
  /usr/bin/time -v \
    "$TRACEE_BIN" \
      --policy "${SCRIPT_DIR}/rules/tracee-bench-policy.yaml" \
      --metrics \
      2>"$time_output" &
  pid=$!

  sample_proc "$pid" "tracee" &
  local sampler_pid=$!

  log "Running workload for ${WORKLOAD_DURATION}..."
  /tmp/ebpf-guard-workload-gen-"${TIMESTAMP}" \
    --duration "${WORKLOAD_DURATION}" \
    --intensity "${INTENSITY}" \
    --seed "${SEED}" \
    --output "${WORKLOAD_OUTPUT}" || true

  kill "$pid" 2>/dev/null || true
  wait "$pid" 2>/dev/null || true
  kill "$sampler_pid" 2>/dev/null || true
  wait "$sampler_pid" 2>/dev/null || true

  local peak_rss_kb cpu_pct
  peak_rss_kb=$(grep "Maximum resident" "$time_output" | awk '{print $NF}' || echo "0")
  cpu_pct=$(grep "Percent of CPU" "$time_output" | awk '{print $NF}' | tr -d '%' || echo "0")
  local peak_rss_mb
  peak_rss_mb=$(echo "scale=1; $peak_rss_kb / 1024" | bc 2>/dev/null || echo "N/A")

  append_result "Tracee ${TRACEE_VERSION}" "N/A" "N/A" "${cpu_pct}" "${peak_rss_mb}" "N/A" "perf stat"
  log "Tracee: done (cpu=${cpu_pct}%, rss=${peak_rss_mb}MB)"
}

# ─── Main ─────────────────────────────────────────────────────────────────────
main() {
  log "════════════════════════════════════════════════════════════════"
  log "  ebpf-guard Comparative Benchmark Harness"
  log "  Timestamp : ${TIMESTAMP}"
  log "  Workload  : duration=${WORKLOAD_DURATION} intensity=${INTENSITY} seed=${SEED}"
  log "  Output    : ${OUTPUT_DIR}"
  log ""
  log "  METHODOLOGY NOTE"
  log "  ─────────────────────────────────────────────────────────────"
  log "  In-process Go benchmarks (ebpf-guard) eliminate OS scheduling"
  log "  noise and JIT warm-up differences. External tool measurements"
  log "  use /usr/bin/time -v (peak RSS) and /proc/<pid>/stat (CPU%)."
  log "  All runs use the same pinned workload (seed=${SEED})."
  log "  Pinned versions: Falco ${FALCO_VERSION}, Tetragon ${TETRAGON_VERSION}, Tracee ${TRACEE_VERSION}."
  log "════════════════════════════════════════════════════════════════"

  # Check for required tools.
  for tool in go bc awk; do
    command -v "$tool" >/dev/null 2>&1 || die "Required tool not found: $tool"
  done

  if ! command -v /usr/bin/time >/dev/null 2>&1; then
    warn "/usr/bin/time not found — external agent CPU/RSS measurements will be unavailable"
    warn "Install with: apt-get install time"
  fi

  init_output
  build_workload_gen

  # Dispatch to requested agent(s).
  if [[ -z "$AGENT" ]] || [[ "$AGENT" == "ebpf-guard" ]]; then run_ebpf_guard; fi
  if [[ -z "$AGENT" ]] || [[ "$AGENT" == "falco"      ]]; then run_falco;      fi
  if [[ -z "$AGENT" ]] || [[ "$AGENT" == "tetragon"   ]]; then run_tetragon;   fi
  if [[ -z "$AGENT" ]] || [[ "$AGENT" == "tracee"     ]]; then run_tracee;     fi

  log ""
  log "════════════════════════════════════════════════════════════════"
  log "  Results written to:"
  log "    CSV: ${CSV_FILE}"
  log "    MD:  ${MD_FILE}"
  log ""
  cat "$MD_FILE"
  log "════════════════════════════════════════════════════════════════"

  # Clean up workload generator binary.
  rm -f /tmp/ebpf-guard-workload-gen-"${TIMESTAMP}" || true
}

main "$@"
